import { ADD_TO_AVAILABLE_COCTAILS } from './types'


export const addToAvialableCoctails = (filters, coctails) => {

    if (!!filters && filters.length > 0) {
        coctails = coctails.filter(coctail => filters.find(id => coctail.compositionIDS.find(ingridientID => ingridientID === id)))
        return {
            type: ADD_TO_AVAILABLE_COCTAILS,
            payload: coctails,
        }

    } else if (filters.length === 0) {
        return {
            type: ADD_TO_AVAILABLE_COCTAILS,
            payload: [],
        }
    }
}