import { SAVE_RANDOM_COCTAIL, LOAD_RANDOM_COCTAIL } from './types'


export function addRandomCoctail(dataFromServer) {
    return {
        type: SAVE_RANDOM_COCTAIL,
        payload: dataFromServer,
    }
}


export const loadRandomCoctail = () => {
    return {
        type: LOAD_RANDOM_COCTAIL,
    }
}