import { takeEvery, put, call } from 'redux-saga/effects'
import { LOAD_RANDOM_COCTAIL, LOAD_INITIAL_DATA} from '../actions/types'
import { showLoader, hideLoader } from '../actions/toggle-loader'
import { addRandomCoctail } from '../actions/fetchCoctail'
import { saveInitialData } from '../actions/addInitialData'
import TheCoctailDb from '../services/the-coctail-db'
import InitialJson from "../data/data.json"


function fetchData() {
    const coctailDb = new TheCoctailDb()

    return (
        coctailDb
            .getRandomCoctail()
            .then(({ drinks }) => drinks[0])
            .catch(function (error) {
                console.log(error)
            })
    )
}

function* workerLoadData() {
    yield put(showLoader())
    const dataFromServer = yield call(fetchData)
    yield put(addRandomCoctail(dataFromServer))
    yield put(hideLoader())
}

export function* watchLoadData() {
    yield takeEvery(LOAD_RANDOM_COCTAIL, workerLoadData)
}




function* workerLoadInitialData() {
    yield put(showLoader())
    yield put(saveInitialData(InitialJson))
    yield put(hideLoader())
}

export function* watchLoadInitialData() {
    yield takeEvery(LOAD_INITIAL_DATA, workerLoadInitialData)
}