import React from 'react'
import { useDispatch, useSelector } from 'react-redux'
import './RandomCoctails.scss'
import RandomCoctailItem from '../../components/RandomCoctailsItem'
import { loadRandomCoctail } from '../../actions/fetchCoctail'
import Loader from '../../components/Loader/Loader'


const RandomCoctails = () => {
    const dispatch = useDispatch()
    const coctailData = useSelector(store => store.fetchedCoctails.fetchedPosts)
    const loading = useSelector(store => store.app.loading)
    const isEmpty = useSelector(store => store.fetchedCoctails.isEmpty)

    const getLoadCoctail = () => { dispatch(loadRandomCoctail()) }

    return (
        <div className="">
            <div className="random-coctails">
                <div className="container">
                    <button className="random-coctails__btn" onClick={getLoadCoctail}>Получить случайный коктейль</button>
                </div>
            </div>
            {loading && <Loader />}
            {!isEmpty && <RandomCoctailItem coctailData={coctailData} key={coctailData.idDrink} />}
        </div>
    )
}


export default RandomCoctails