import React from 'react'
import { connect } from 'react-redux'
import './Ingredients.scss'
import Ingredient from '../../components/Ingredient'
import { AddToBar } from '../../actions/addToBar'


const Ingredients = ({bar, AddToBar, data}) => {
    const addBar = (item) => {
        if (!bar.some(elem => elem.id === item.id)) {
            AddToBar(item)
        }
    }

    const ingredients = data.map((item) => {
        return (
            <Ingredient
                item={item}
                key={item.id}
                addBar={addBar}
            />
        )
    })

    return (
        <div className="ingredients">
            <div className="container">
                <h2 className="ingredients__title">Ингредиенты</h2>
                <div className="my-bar__ingredients">
                    <ul className="ingredients__list">
                        {ingredients}
                    </ul>
                </div>
            </div>
        </div>
    )
}


const mapStateToProps = store => {
    return {
        data: store.data.ingredients,
        bar: store.bar
    }
}


const mapDispatchToProps = dispatch => {
    return {
        AddToBar: ingridient => dispatch(AddToBar(ingridient))
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(Ingredients)