import {SAVE_INITIAL_DATA} from '../actions/types'

const initialState = {
    drinks: [],
    ingredients: [],
}


export function dataReducer(state = initialState, action) {
    switch (action.type) {
        case SAVE_INITIAL_DATA:
            return {
                ...state,
                drinks: action.payload.drinks,
                ingredients: action.payload.ingredients
            }
        default:
            return state
    }
}