import React, { useEffect } from 'react'
import { useDispatch } from 'react-redux'
import './AvailableCoctails.scss'
import Coctail from '../Coctail'
import { addToAvialableCoctails } from '../../actions/addToAvialableCoctails'


const AvailableCoctails = ({ coctails, bar, availableCoctails }) => {
    const dispatch = useDispatch()
    let filters = bar.map(elem => elem.id)

    useEffect(() => {
        dispatch((addToAvialableCoctails(filters, coctails)))
    }, [bar] )

    return (
        <div className="available-coctails">
            <div className="container">
                <h2 className="available-coctails__title">Доступные коктейли</h2>
                <div className="available-coctails__blocks">
                    {availableCoctails.map((item) => <Coctail key={item.idDrink} coctailInfo={item} />)}
                </div>
            </div>
        </div>
    )
}


export default AvailableCoctails