import React from 'react'
import { connect } from 'react-redux'
import BarItem from '../../components/BarItem'
import './Bar.scss'
import { AddToBasket } from '../../actions/addBasket'
import { removeIngridientInBar } from '../../actions/removeIngridientInBar'


const Bar = ({ bar, removeIngridientInBar, coctails, basket, setAddToBasket }) => {

    const addBasket = (barItem) => {
        if (basket.length === 0) {
            setAddToBasket(barItem)
        } else {
            let contain = basket.some((element) => { return element.id === barItem.id })
            if (!contain) {
                setAddToBasket(barItem)
            }
        }
    }

    const removeFromBar = (barItem) => {
        let values = bar.filter(function (x) { return x.name !== barItem.name })
        removeIngridientInBar(values)
    }

    const generateBarItem = () => {

        if (bar.length > 0) {
            return (bar.map((item) => {
                return (
                    <BarItem
                        {...item}
                        bar={bar}
                        coctails={coctails}
                        removeFromBar={removeFromBar}
                        addBasket={addBasket}
                        key={item.id}
                    />
                )
            }))
        }
    }

    return (
        <div className="my-bar">
            <div className="container my-bar__container">
                <h2 className="my-bar__title">Мой бар</h2>
                <div className="my-bar__blocks">
                    {generateBarItem()}
                </div>
            </div>
        </div>
    )
}


const mapStateToProps = store => {
    return {
        bar: store.bar,
        basket: store.basket,
    }
}


const mapDispatchToProps = dispatch => {
    return {
        removeIngridientInBar: ingridient => dispatch(removeIngridientInBar(ingridient)),
        setAddToBasket: goods => dispatch(AddToBasket(goods)),
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(Bar)