import React from 'react'
import './About.scss'


const About = () => {
    return (
        <div className="about">
            <div className="container">
                <h1 className="about__title">О Приложении</h1>
                <p className="about__text">Тестовое приложение написано с использованием:</p>
                <ul>
                    <li>React</li>
                    <li>React-router</li>
                    <li>Redux</li>
                    <li>Redux-saga</li>
                </ul>
                <p>На странице TheCoctailDB используются хуки <b>useDispatch</b> и  <b>useSelector</b> из <b>react-redux</b>.
                    Также происходит запрос к API https://www.thecocktaildb.com/ для выдачи рандомного коктейля.
                </p>
            </div>
        </div>
    )
}

export default About