import React, { useEffect } from 'react'
import { useDispatch, connect } from 'react-redux'
import { Route, Switch } from 'react-router-dom'
import './App.scss'
import About from '../../components/About'
import FullBasket from '../../components/FullBasket'
import Header from '../../components/Header'
import Footer from '../../components/Footer'
import Bar from '../Bar'
import AvailableCoctails from '../../components/AvailableCoctails'
import FullCategory from '../FullCategory'
import CoctailDetail from '../../components/CoctailDetail'
import Ingredients from '../Ingredients'
import RandomCoctails from '../RandomCoctails'
import { loadInitialData } from '../../actions/addInitialData'
import Loader from '../../components/Loader/Loader'


const App = (props) => {
	const { data, basket, totalPrice, availableCoctails, app, bar } = props
	const dispatch = useDispatch()

	useEffect(() => {
		dispatch(loadInitialData())
	}, [])


	return (
		<>
			<div className="content">
				<Header />

				{app.loading && <Loader />}

				<Switch>
					<Route exact path='/'>
						<Ingredients coctails={data.drinks} />

						<Bar />

						{/* <AvailableCoctails availableCoctails={availableCoctails} /> */}
						<AvailableCoctails 
						availableCoctails={availableCoctails}
						coctails={data.drinks} 
						bar={bar}
						/>
					</Route>

					<Route exact path='/Coctail-app/about'>
						<About />
					</Route>

					<Route path='/Coctail-app/the-coctail-db'>
						<RandomCoctails />
					</Route>

					<Route path='/Coctail-app/full-basket'>
						<FullBasket
							totalPrice={totalPrice}
							basket={basket}
							ingredients={data.ingredients}
						/>
					</Route>

					<Route
						path='/Coctail-app/categories/:id'
						render={({ match }) => {
							const { id } = match.params;
							return <FullCategory coctailCategory={id} />
						}} />

					<Route
						path='/Coctail-app/coctail/:id'
						render={({ match }) => {
							const { id } = match.params;
							return <CoctailDetail coctailNumber={id} coctails={data.drinks} />
						}} />
				</Switch>
			</div>
			<Footer />
		</>
	)
}


const mapStateToProps = store => {
	return {
		app: store.app,
		data: store.data,
		basket: store.basket,
		bar: store.bar,
		availableCoctails: store.availableCoctails.prod,
		totalPrice: store.basket.reduce((sum, p) => { sum += p.price * p.quantity; return sum; }, 0)
	}
}

export default connect(mapStateToProps)(App);